import './styles/main.css';import {cloneConfig} from './core/defaults.js';import {loadImage,drawImageToCanvas,getImageData} from './core/imageLoader.js';import {buildPreviewData,generateDocument} from './core/pipeline.js';import {generateSvg,downloadFile} from './core/svgExport.js';import {PRESETS,applyPreset} from './core/presets.js';import {showImageData} from './ui/previewCanvas.js';import {setSvgPreview} from './ui/svgPreview.js';import {saveSettings,loadSettings,exportSettings,importSettings} from './ui/storage.js';
let config=loadSettings()||cloneConfig(),source=null,lastDoc=null,lastSvg='';
const app=document.querySelector('#app');app.innerHTML=`<aside><h1>HatchForge</h1><p>Offline vector hatching for laser engraving.</p><section><h2>Image</h2><input id=file type=file accept="image/png,image/jpeg,image/webp"><label>Max px <input data-path="image.maxDimension" type=number value="${config.image.maxDimension}"></label><div id=size>Load an image.</div></section><section><h2>Presets</h2><select id=preset>${Object.keys(PRESETS).map(p=>`<option>${p}</option>`).join('')}</select><button id=applyPreset>Apply</button></section><section><h2>Tone</h2>${range('tone.brightness',-100,100,1)}${range('tone.contrast',.2,2.5,.05)}${range('tone.gamma',.2,3,.05)}${check('tone.invert','Invert')}</section><section><h2>Posterize & Mask</h2>${range('posterize.levels',3,8,1)}${range('mask.whiteThreshold',180,255,1)}${check('mask.useAlpha','Use alpha mask')}${check('mask.removeWhite','Remove white bg')}<label>Min region area <input data-path="mask.minRegionArea" type=number value="${config.mask.minRegionArea}"></label></section><section><h2>Accumulation</h2>${check('accumulation.cumulativeMode','Cumulative by threshold masks')}${check('accumulation.inverted','Inverted accumulation')}<select data-path="accumulation.cumulativeStrategy"><option>byThresholdMask</option><option>byRegionTone</option><option>globalLevelAccumulation</option></select></section><section><h2>Hatching per level</h2><div id=hatchControls></div></section><section><h2>Edges / Details / Border</h2>${check('edges.internal','Internal edges')}${range('edges.minToneJump',1,5,1)}${check('details.enabled','Detail edges')}${range('details.detailThreshold',10,100,1)}${check('border.enabled','Outer border')}${range('border.strokeWidth',.2,5,.1)}</section><section><h2>Export</h2>${range('export.widthMm',20,400,1)}${check('export.allBlack','All black SVG')}<button id=generate>Generate vector</button><button id=download>Download SVG</button><button id=copy>Copy SVG</button><button id=save>Save settings</button><button id=reset>Reset</button></section></aside><main><nav><button data-tab=original>Original</button><button data-tab=gray>Gray</button><button data-tab=poster>Posterized</button><button data-tab=vector>Vector SVG</button><button data-tab=debug>Debug</button></nav><div class=stage><canvas id=original></canvas><canvas id=gray hidden></canvas><canvas id=poster hidden></canvas><div id=vector hidden></div><pre id=debug hidden></pre></div><section class=layers><h2>Layers</h2><div id=layers></div></section><footer id=status>Ready.</footer></main>`;
function range(path,min,max,step){return `<label>${path} <input data-path="${path}" type=range min="${min}" max="${max}" step="${step}" value="${get(path)}"><output>${get(path)}</output></label>`}function check(path,label){return `<label><input data-path="${path}" type=checkbox ${get(path)?'checked':''}> ${label}</label>`}function get(path){return path.split('.').reduce((o,k)=>o?.[k],config)}function set(path,val){const a=path.split('.'),k=a.pop(),o=a.reduce((x,p)=>x[p],config);o[k]=val}
function ensureHatchLevels(){for(let i=1;i<config.posterize.levels;i++)if(!config.hatching.levels[i])config.hatching.levels[i]={...config.hatching.levels.at(-1),spacing:Math.max(3,18-i*2),angle:(i%2?45:-45),secondAngle:i>3?90:null,color:['#3478f6','#28a745','#f59f00','#d6336c','#111','#7950f2','#0ca678'][i-1]||'#111'}}
function hatchUI(){ensureHatchLevels();hatchControls.innerHTML='';for(let i=1;i<config.posterize.levels;i++){const c=config.hatching.levels[i];hatchControls.insertAdjacentHTML('beforeend',`<fieldset><legend>Level ${i}</legend><label><input data-path="hatching.levels.${i}.enabled" type=checkbox ${c.enabled?'checked':''}> enabled</label>${['spacing','angle','strokeWidth','jitter','minSegmentLength','sampleStep'].map(k=>`<label>${k}<input data-path="hatching.levels.${i}.${k}" type=number step=.1 value="${c[k]}"></label>`).join('')}<label>secondAngle <input data-path="hatching.levels.${i}.secondAngle" placeholder="empty" value="${c.secondAngle??''}"></label></fieldset>`)}}
hatchUI();let timer;app.addEventListener('input',e=>{const p=e.target.dataset.path;if(!p)return;let v=e.target.type==='checkbox'?e.target.checked:e.target.value;if(e.target.type==='range'||e.target.type==='number')v=Number(v);if(v==='')v=null;set(p,v);if(p==='posterize.levels')hatchUI();e.target.nextElementSibling&&e.target.nextElementSibling.tagName==='OUTPUT'&&(e.target.nextElementSibling.textContent=v);clearTimeout(timer);timer=setTimeout(updatePreviews,200)});
file.onchange=async()=>{const f=file.files[0];if(!f)return;const img=await loadImage(f);source=drawImageToCanvas(img,config.image.maxDimension);original.width=source.width;original.height=source.height;original.getContext('2d').drawImage(source.canvas,0,0);size.textContent=`Original ${source.originalWidth}×${source.originalHeight}; processed ${source.width}×${source.height}`;updatePreviews()};
async function updatePreviews(){if(!source)return;const p=buildPreviewData(getImageData(source.canvas),config);showImageData(gray,p.adjustedImageData);showImageData(poster,p.posterImageData);debug.textContent=JSON.stringify({size:[p.levelMap.width,p.levelMap.height],levels:p.levelMap.levels,thresholds:p.levelMap.thresholds,maskPixels:p.mask.reduce((a,b)=>a+b,0)},null,2)}
generate.onclick=()=>{if(!source)return alert('Load an image first');lastDoc=generateDocument(getImageData(source.canvas),config);lastSvg=generateSvg(lastDoc.model,config.export);setSvgPreview(vector,lastSvg);layers.innerHTML=lastDoc.layers.map(l=>`<label><input type=checkbox checked data-layer="${l.id}"> <span style="color:${l.color}">${l.name}</span> ${l.stats.segments||l.stats.points||0}</label>`).join('');status.textContent=`Generated ${lastDoc.stats.segments} segments in ${lastDoc.stats.ms.toFixed(0)} ms. ${lastDoc.stats.warnings.join(' ')}`;debug.textContent=JSON.stringify(lastDoc.stats,null,2)};
download.onclick=()=>lastSvg&&downloadFile('hatchforge.svg',lastSvg);copy.onclick=()=>lastSvg&&navigator.clipboard.writeText(lastSvg);save.onclick=()=>{saveSettings(config);status.textContent='Settings saved.'};reset.onclick=()=>{config=cloneConfig();location.reload()};applyPreset.onclick=()=>{config=applyPreset(preset.value);hatchUI();status.textContent=`Preset applied: ${preset.value}`;updatePreviews()};document.querySelector('nav').onclick=e=>{if(!e.target.dataset.tab)return;['original','gray','poster','vector','debug'].forEach(id=>document.getElementById(id).hidden=id!==e.target.dataset.tab)};layers.onclick=e=>{if(e.target.dataset.layer){const g=vector.querySelector(`#${e.target.dataset.layer}`);if(g)g.style.display=e.target.checked?'':'none'}};
